      let val = try RestoreFootprintOpXDR.fromTxRep(map, prefix: "\(prefix).restoreFootprintOp")
      return .restoreFootprintOp(val)
    default:
      throw TxRepError.invalidValue(key: discKey)
    }
  }
}
